"use client";

import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export function FormLayout({
  children,
  className,
}: {
  children: ReactNode;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "space-y-10",
        className
      )}
    >
      {children}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

interface FormSectionProps {
  children: ReactNode;
  title?: string;
  description?: string;
  className?: string;
}

export function FormSection({
  title,
  description,
  children,
  className
}: FormSectionProps) {
  return (
    <div className="space-y-4">
      <div>
        <h3 className="text-lg font-semibold text-foreground">{title}</h3>
        {description && (
          <p className="text-sm text-muted-foreground">{description}</p>
        )}
      </div>

      {/* Reduced spacing for cleaner alignment */}
      <div className={cn("space-y-3", className)}>{children}</div>
    </div>
  );
}

"use client";

import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

export function FormGrid({
  columns = 2,
  children,
}: {
  columns?: 1 | 2 | 3 | 4;
  children: ReactNode;
}) {
  return (
    <div
      className={cn(
        "grid gap-4",
        columns === 1 && "grid-cols-1",
        columns === 2 && "grid-cols-1 md:grid-cols-2",
        columns === 3 && "grid-cols-1 md:grid-cols-3",
        columns === 4 && "grid-cols-1 md:grid-cols-4"
      )}
    >
      {children}
    </div>
  );
}

/** @deprecated Use FormGrid instead. */
export const FormColumns = FormGrid;

"use client";

import { FieldGroup } from "@/components/ui/field";
import { cn } from "@/lib/utils";

interface FormRowProps {
  children: React.ReactNode;
  className?: string;
}

export function InlineFieldRow({ children, className }: FormRowProps) {
  return (
    <FieldGroup
      className={cn("flex flex-row gap-4 items-start w-full", className)}
    >
      {children}
    </FieldGroup>
  );
}

/** @deprecated Use InlineFieldRow instead. */
export const FormRow = InlineFieldRow;

"use client";

export function SectionDivider({ label }: { label?: string }) {
  return (
    <div className="flex items-center gap-2 my-4">
      <div className="h-px flex-1 bg-border" />
      {label && <span className="text-xs text-muted-foreground">{label}</span>}
      <div className="h-px flex-1 bg-border" />
    </div>
  );
}

/** @deprecated Use SectionDivider instead. */
export const FormDivider = SectionDivider;

"use client";

import type { ReactNode } from "react";

import { FieldSeparator } from "@/components/ui/field";

export function FormActionBar({ children }: { children: ReactNode }) {
  return (
    <div className="pt-4">
      <FieldSeparator className="mb-2" />
      {children}
    </div>
  );
}

/** @deprecated Use FormActionBar instead. */
export const FormActions = FormActionBar;

"use client";

import type { ReactNode } from "react";

import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";

type FieldGroupProps = {
  label?: string;
  error?: string;
  description?: string;
  orientation?: "horizontal" | "vertical" | "responsive" | null | undefined;
  children: ReactNode;
  className?: string;
};

export function FieldGroup({
  label,
  error,
  description,
  children,
  orientation,
  className,
}: FieldGroupProps) {
  return (
    <Field className={className ?? "space-y-1.5"} orientation={orientation}>
      {label && <FieldLabel>{label}</FieldLabel>}
      {children}
      {description && <FieldDescription>{description}</FieldDescription>}
      {error && <FieldError>{error}</FieldError>}
    </Field>
  );
}

/** @deprecated Use FieldGroup instead. */
export function FormFieldWrapper(props: FieldGroupProps) {
  return <FieldGroup {...props} />;
}
